              cfg: ctx.cfg,
              runtime,
              channel: "nostr",
              channelLabel: "Nostr",
              accountId: account.accountId,
              peer: {
                kind: "direct",
                id: senderPubkey,
              },
              senderId: senderPubkey,
              senderAddress: `nostr:${senderPubkey}`,
              recipientAddress: `nostr:${account.publicKey}`,
              conversationLabel: senderPubkey,
              rawBody: text,
              messageId: meta.eventId,
