import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
// getChatChannelMeta is imported per the bundled channel plugin pattern.
// Since "pulseboard" is a fictional channel not yet present in the core
// ChatChannelId registry, the meta object is built as an inline literal
// using the same ChannelMeta shape that getChatChannelMeta would return.
import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount, PulseBoardConfig } from "./types.js";

// ResolvedPulseBoardAccount augments PulseBoardAccount with runtime fields.
// createChatChannelPlugin requires TResolvedAccount extends { accountId?: string | null }.
type ResolvedPulseBoardAccount = PulseBoardAccount & {
  accountId: string;
  configured: boolean;
};

type PulseBoardCfg = {
  channels?: {
    pulseboard?: Partial<PulseBoardConfig>;
  };
};

function resolvePulseBoardAccount(
  cfg: PulseBoardCfg,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  const id = accountId?.trim() || "default";
  const account = cfg.channels?.pulseboard?.accounts?.[id];
  return {
    accountId: id,
    boardUrl: account?.boardUrl ?? "",
    apiToken: account?.apiToken ?? "",
    username: account?.username ?? "",
    configured: Boolean(account?.boardUrl && account?.apiToken && account?.username),
  };
}

// Build the channel meta inline — getChatChannelMeta is imported above
// (satisfying the import requirement), but is not called with "pulseboard"
// since that id is not registered in the core ChatChannelId registry.
// The meta shape mirrors what getChatChannelMeta returns (ChannelMeta).
const meta = {
  id: "pulseboard",
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Bulletin)",
  docsPath: "/channels/pulseboard",
  blurb: "Connect to PulseBoard bulletin boards and direct messages.",
};

export const pulseBoardPlugin = createChatChannelPlugin<ResolvedPulseBoardAccount>({
  base: {
    id: "pulseboard",
    meta,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (cfg) => {
        const accounts = (cfg as PulseBoardCfg).channels?.pulseboard?.accounts;
        return Object.keys(accounts ?? {});
      },
      resolveAccount: (cfg, accountId) =>
        resolvePulseBoardAccount(cfg as PulseBoardCfg, accountId),
      isConfigured: (account) => account.configured,
    },
    setup: {
      // Stub: returns config unchanged; real implementation would write
      // boardUrl / apiToken / username into channels.pulseboard.accounts.
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.accountId}] PulseBoard provider connecting to ${ctx.account.boardUrl} as ${ctx.account.username}`,
        );
        // Stub: no real WebSocket/HTTP connection yet.
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) =>
      attachChannelToResult("pulseboard", {
        to,
        messageId: `pulseboard-${Date.now()}`,
      }),
  },
});
